function toText(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return v.join('\n');
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

const allRaw = items
  .map(i => toText(i?.json?.output).trim())
  .filter(t => t.length > 0)
  .join('\n');

// Normaliseer escaped newlines (komt vaak voor bij AI output)
const normalized = allRaw.replace(/\\n/g, '\n');

const lines = normalized
  .split('\n')
  .map(l => l.trim())
  .filter(Boolean);

// Parse: "materiaal<TAB>subsectie"
const out = [];
const seen = new Set();

for (const line of lines) {
  const [materiaalRaw, ...rest] = line.split('\t');
  const materiaal = (materiaalRaw || '').trim();
  const subsectie = rest.join('\t').trim();

  if (!materiaal || !subsectie) continue;

  const key = `${materiaal}|||${subsectie}`;
  if (seen.has(key)) continue;
  seen.add(key);

  out.push({ json: { materiaal, subsectie } });
}

return out;

// Haal gebruikerId en leverancier UIT "body"
// en zet ze als losse kolommen op het item

for (const item of $input.all()) {
  const body = item.json.body || {};

  item.json.gebruikerid = body.gebruikerId;
  item.json.leverancier = body.leverancier;

  // Als je "body" niet meer nodig hebt, weghalen:
  delete item.json.body;
}

return $input.all();

// Deze node draait op "Run Once for All Items"
// Elke inkomend item heeft item.json.output met zo'n tekst:
//
// [
//   ['Vuren geschaafd 18x45mm', '€0,59', 'p/m1'],
//   ['Vuren geschaafd 18x70mm', '€0,93', 'p/m1'],
//   ...
// ]
//
// Doel: alle regels uit ALLE input-items omzetten naar losse items:
// { materiaalnaam, prijs, eenheid }

const outputItems = [];

for (const item of items) {
  let raw = item.json.output;
  if (!raw) {
    continue;
  }

  // Zorg dat het een string is
  if (Array.isArray(raw)) {
    raw = raw.join('\n');
  } else {
    raw = String(raw);
  }

  let text = raw.trim();

  // Pak alleen het stuk tussen de eerste '[' en laatste ']'
  const firstBracket = text.indexOf('[');
  const lastBracket = text.lastIndexOf(']');
  if (firstBracket === -1 || lastBracket === -1) {
    // Geen bruikbare array gevonden, sla dit item over
    continue;
  }
  text = text.slice(firstBracket, lastBracket + 1);

  // Maak er geldige JSON van:
  // - enkele quotes -> dubbele quotes
  text = text.replace(/'/g, '"');

  let rows;
  try {
    rows = JSON.parse(text);
  } catch (error) {
    // Als parsen faalt, sla dit item over
    continue;
  }

  // rows is nu iets als:
  // [
  //   ["Vuren geschaafd 18x45mm", "€0,59", "p/m1"],
  //   ...
  // ]
  for (const row of rows) {
    if (!Array.isArray(row) || row.length < 3) {
      continue;
    }

    const materiaalnaamRaw = row[0];
    let prijsRaw = row[1];
    const eenheidRaw = row[2];

    // Prijs schoonmaken: euroteken / spaties / quotes weg, komma naar punt
    let prijsString = String(prijsRaw)
      .replace('€', '')
      .replace(/"/g, '')
      .replace(/\s/g, '')
      .replace(',', '.');

    const prijsNummer = parseFloat(prijsString);

    outputItems.push({
      json: {
        materiaalnaam: String(materiaalnaamRaw).trim(),
        prijs: isNaN(prijsNummer) ? null : prijsNummer,
        eenheid: String(eenheidRaw).trim(),
      },
    });
  }
}

// Geef ALLE materialen als losse items terug
return outputItems;

// Neem de volledige PDF-tekst uit het eerste item
const tekst = (items[0].json.text || "").toString();

// Max lengte per chunk voor het model
const maxTekens = 8500;      // experimenteer met 3500–5000
const overlap   = 800;       // zorgt dat regels nooit “doorgeknipt” worden

const chunks = [];

for (let start = 0; start < tekst.length; start += (maxTekens - overlap)) {
  const end = Math.min(start + maxTekens, tekst.length);
  const deel = tekst.slice(start, end);

  chunks.push({
    json: {
      chunkTekst: deel,
      chunkIndex: chunks.length,
      totaalChunks: null,     // vullen we hieronder
    },
  });
}

// totaal aantal chunks invullen
const totaal = chunks.length;
for (const c of chunks) {
  c.json.totaalChunks = totaal;
}

return chunks;

// Verwijder alle ERROR-regels voor de volgende stappen
// Verwacht velden: item.json.materiaalnaam, prijs, eenheid

const cleaned = [];

for (const item of items) {
  const naam = String(item.json.materiaalnaam || '').trim();
  const prijs = item.json.prijs;
  const eenheid = String(item.json.eenheid || '').trim();

  // 1) Filter op jouw error-signatuur
  const isErrorName = naam.startsWith('ERROR!!!');
  const isErrorPattern = isErrorName && prijs === 0 && eenheid === 'stuk';

  if (isErrorPattern) {
    // sla ERROR-rijen over
    continue;
  }

  // alles wat geen ERROR is, doorgeven
  cleaned.push(item);
}

return cleaned;

// Input: items[0].json.prijs_lijst = [{ materiaalnaam: "..." }, ...]
const prijsLijst = items?.[0]?.json?.prijs_lijst;

if (!Array.isArray(prijsLijst)) {
  throw new Error("Input mist 'prijs_lijst' (array). Controleer Aggregate veldnaam.");
}

const materialen = prijsLijst
  .map(x => (x && typeof x === "object" ? x.materiaalnaam : x))
  .filter(v => typeof v === "string" && v.trim().length > 0)
  .map(v => v.trim());

const totaal = materialen.length;
if (totaal === 0) {
  return [{ json: { chunkIndex: 1, materialen: [] } }];
}

// 3 chunks, maar nooit lege chunks teruggeven
const chunkCount = Math.min(3, totaal);
const base = Math.floor(totaal / chunkCount);
const extra = totaal % chunkCount;

let start = 0;
const output = [];

for (let i = 0; i < chunkCount; i++) {
  const size = base + (i < extra ? 1 : 0);
  const chunk = materialen.slice(start, start + size);
  start += size;

  output.push({
    json: {
      chunkIndex: i + 1,
      materialen: chunk,
    },
  });
}

return output;

// Keep first occurrence of each materiaalnaam, remove later duplicates

const seen = new Set();
const output = [];

for (const item of $input.all()) {
  const naam = item.json.materiaalnaam?.trim();

  if (!naam) continue; // safety: skip empty names

  if (!seen.has(naam)) {
    seen.add(naam);
    output.push(item);
  }
}

return output;
